let raw = $.steps.fetchFlowList.output || '';
let flows = [];
try {
  const parsed = JSON.parse(raw);
  flows = parsed.flows || parsed.data || [];
} catch(e) {
  const lines = raw.split('\n').filter(l => l.trim().length > 0);
  flows = lines.map(l => ({ name: l.trim() }));
}
const totalFlows = flows.length;
const flowNames = flows.map(f => f.name || f.key || 'unnamed').slice(0, 50);
const flowSummary = flows.slice(0, 30).map((f, i) => (i + 1) + '. ' + (f.name || f.key || 'unnamed')).join('\n');
return { totalFlows, flowNames, flowSummary, rawFlowData: JSON.stringify(flows).slice(0, 6000) };

const data = $.steps.parseFlowList.output;
let prompt = 'You are an automation workflow analyst. You have been given a list of One CLI automation flows (similar to n8n workflows). Analyze this inventory and provide a structured backup report.

';
prompt += 'TOTAL FLOWS: ' + data.totalFlows + '

';
prompt += 'FLOW LIST:
' + data.flowSummary + '

';
prompt += 'RAW DATA:
' + data.rawFlowData + '

';
prompt += 'INSTRUCTIONS:
';
prompt += '- Categorize flows by type (AI, data processing, integrations, etc.)
';
prompt += '- Identify the most common platforms and patterns
';
prompt += '- Note any potential issues (duplicates, naming inconsistencies)
';
prompt += '- Provide a health score (1-10) for the overall flow collection

';
prompt += 'Return ONLY valid JSON:
';
prompt += '{
';
prompt += '  "summary": "2-3 sentence overview of the flow collection",
';
prompt += '  "totalFlows": 0,
';
prompt += '  "categories": [{ "name": "category", "count": 0, "examples": ["flow1"] }],
';
prompt += '  "topPlatforms": ["platform1", "platform2"],
';
prompt += '  "healthScore": 8,
';
prompt += '  "recommendations": ["recommendation1"]
';
prompt += '}';
return { prompt };

let raw = $.steps.aiAnalysis.output || '';
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/\s*```$/i, '').trim();
try { return JSON.parse(raw); } catch(e) { return { summary: raw, totalFlows: 0, categories: [], topPlatforms: [], healthScore: 0, recommendations: [] }; }

const ai = $.steps.parseAI.output;
const data = $.steps.parseFlowList.output;

const blocks = [];
blocks.push({ type: 'header', text: { type: 'plain_text', text: 'Flow Backup Report', emoji: true } });
blocks.push({ type: 'section', fields: [
  { type: 'mrkdwn', text: '*Total Flows:*\n' + data.totalFlows },
  { type: 'mrkdwn', text: '*Health Score:*\n' + (ai.healthScore || 'N/A') + '/10' }
] });
blocks.push({ type: 'divider' });

const summaryText = (ai.summary || 'No summary generated.').slice(0, 1800);
blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Summary:*\n' + summaryText } });

if (ai.categories && ai.categories.length > 0) {
  blocks.push({ type: 'divider' });
  let catText = '*Flow Categories:*\n';
  ai.categories.slice(0, 8).forEach(c => {
    catText += '- *' + c.name + '* (' + c.count + ')';
    if (c.examples && c.examples.length > 0) catText += ': ' + c.examples.slice(0, 2).join(', ');
    catText += '\n';
  });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: catText.slice(0, 1800) } });
}

if (ai.topPlatforms && ai.topPlatforms.length > 0) {
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: '*Top Platforms:* ' + ai.topPlatforms.slice(0, 6).join(', ') } });
}

if (ai.recommendations && ai.recommendations.length > 0) {
  blocks.push({ type: 'divider' });
  let recText = '*Recommendations:*\n';
  ai.recommendations.slice(0, 5).forEach((r, i) => { recText += (i + 1) + '. ' + r + '\n'; });
  blocks.push({ type: 'section', text: { type: 'mrkdwn', text: recText.slice(0, 1800) } });
}

blocks.push({ type: 'divider' });
blocks.push({ type: 'context', elements: [{ type: 'mrkdwn', text: 'Backup report generated by One CLI + Claude AI' }] });

const fallbackText = 'Flow Backup Report: ' + data.totalFlows + ' flows analyzed - ' + (ai.summary || '').slice(0, 100);
return { blocks, fallbackText };
